import React from 'react';

const Cultura = ({ sitios }) => {
    return (
        <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
            <h1 style={{ textAlign: 'center', color: '#2c3e50' }}>Sitios Culturales de La Paz</h1>
            <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', 
                gap: '20px',
                marginTop: '30px'
            }}>
                {sitios && sitios.length > 0 ? (
                    sitios.map((sitio) => (
                        <div key={sitio.id_sitio || sitio.id} style={{ 
                            border: '1px solid #ddd', 
                            borderRadius: '12px', 
                            padding: '20px', 
                            backgroundColor: '#ffffff',
                            boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
                        }}>
                            {/* Intentamos leer 'nombre' o 'NOMBRE' */}
                            <h2 style={{ margin: '0 0 10px 0', color: '#e74c3c' }}>
                                {sitio.nombre || sitio.NOMBRE || "Sin nombre"}
                            </h2>
                            <p style={{ color: '#34495e', lineHeight: '1.5' }}>
                                {sitio.descripcion || sitio.DESCRIPCION || "Sin descripción disponible."}
                            </p>
                            <hr style={{ border: '0', borderTop: '1px solid #eee', margin: '15px 0' }} />
                            <small style={{ color: '#95a5a6', display: 'block' }}>
                                📍 {sitio.direccion || sitio.DIRECCION || "Dirección no especificada"}
                            </small>
                        </div>
                    ))
                ) : (
                    <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '50px' }}>
                        <h3>No se encontraron datos</h3>
                        <p>Verifica que la tabla 'sitios_culturales' tenga registros en PostgreSQL.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Cultura;
